export function chooseLocale(preferredLocales, availableLocales) {
  const available = new Map(availableLocales.map((locale) => [locale.toLowerCase(), locale]));
  for (const preferred of preferredLocales) {
    const match = available.get(preferred.toLowerCase());
    if (match) {
      return match;
    }
  }
  return null;
}

