import { catalogCacheKey } from "./catalog-cache-key.mjs";
import { chooseLocale } from "./locale-choice.mjs";

export class CatalogService {
  constructor({ cache, availableLocales, loadCatalog }) {
    this.cache = cache;
    this.availableLocales = [...availableLocales];
    this.loadCatalog = loadCatalog;
  }

  getCatalog({ tenant, preferredLocales }) {
    const locale = chooseLocale(preferredLocales, this.availableLocales);
    if (locale === null) {
      return Promise.reject(new Error("no acceptable locale"));
    }
    const key = catalogCacheKey({ tenant, preferredLocales });
    return this.cache.get(key, () => this.loadCatalog({ tenant, locale }));
  }
}

