import test from "node:test";
import assert from "node:assert/strict";

import { AsyncSlotCache } from "../src/async-slot-cache.mjs";
import { CatalogService } from "../src/catalog-service.mjs";

function deferred() {
  let resolve;
  const promise = new Promise((onResolve) => {
    resolve = onResolve;
  });
  return { promise, resolve };
}

test("identical preference order reuses the cached catalog object", async () => {
  let loads = 0;
  const service = new CatalogService({
    cache: new AsyncSlotCache(),
    availableLocales: ["en", "fr"],
    async loadCatalog({ tenant, locale }) {
      loads += 1;
      return { tenant, locale };
    }
  });

  const first = await service.getCatalog({ tenant: "a", preferredLocales: ["fr", "en"] });
  const second = await service.getCatalog({ tenant: "a", preferredLocales: ["fr", "en"] });
  assert.equal(second, first);
  assert.equal(first.locale, "fr");
  assert.equal(loads, 1);
});

test("tenant identity remains part of the cache boundary", async () => {
  let loads = 0;
  const service = new CatalogService({
    cache: new AsyncSlotCache(),
    availableLocales: ["en"],
    async loadCatalog({ tenant, locale }) {
      loads += 1;
      return { tenant, locale };
    }
  });

  const left = await service.getCatalog({ tenant: "left", preferredLocales: ["en"] });
  const right = await service.getCatalog({ tenant: "right", preferredLocales: ["en"] });
  assert.notEqual(left, right);
  assert.equal(loads, 2);
});

test("concurrent successful misses share one loader", async () => {
  const gate = deferred();
  const cache = new AsyncSlotCache();
  let loads = 0;
  const first = cache.get("shared", async () => {
    loads += 1;
    return gate.promise;
  });
  const second = cache.get("shared", async () => {
    loads += 1;
    return { impossible: true };
  });

  await Promise.resolve();
  assert.equal(loads, 1);
  const value = { version: 7 };
  gate.resolve(value);
  assert.equal(await first, value);
  assert.equal(await second, value);
  assert.equal(cache.peek("shared"), value);
});
